1	const PROCESSING_FEE = 5;
2	const DEDUCTIBLE = 100;
3	
4	const BASE_PREMIUMS: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	  potion: 40,
9	  rune: 25,
10	  moonstone: 25,
11	};
12	
13	const INSURANCE_VALUES: Record<string, number> = {
14	  sword: 1000,
15	  amulet: 600,
16	  staff: 800,
17	  potion: 400,
18	  rune: 250,
19	  moonstone: 250,
20	};
21	
22	const MAIN_ITEM_TYPES = ["sword", "amulet", "staff", "potion"];
23	const COMPONENT_BLOCK_SIZE = 3;
24	const COMPONENT_BLOCK_PREMIUM = 60;
25	
26	const isMainItem = (item: any): boolean =>
27	  MAIN_ITEM_TYPES.includes(item.type);
28	
29	const premiumForType = (type: string): number =>
30	  BASE_PREMIUMS[type] ?? 0;
31	
32	const countByType = (items: any[]): Record<string, number> => {
33	  const counts: Record<string, number> = {};
34	  for (const item of items) {
35	    counts[item.type] = (counts[item.type] ?? 0) + 1;
36	  }
37	  return counts;
38	};
39	
40	const calculateComponentPremium = (components: any[]): number => {
41	  const countsByType = countByType(components);
42	  return Object.entries(countsByType).reduce(
43	    (total, [type, count]) =>
44	      total +
45	      (count === COMPONENT_BLOCK_SIZE
46	        ? COMPONENT_BLOCK_PREMIUM
47	        : count * premiumForType(type)),
48	    0,
49	  );
50	};
51	
52	const calculateItemSurcharges = (item: any): number => {
53	  const base = premiumForType(item.type);
54	  return (item.cursed ? base * 0.5 : 0) + (item.enchantment >= 5 ? base * 0.3 : 0);
55	};
56	
57	const calculateQuotePremium = (
58	  step: any,
59	  customer: any,
60	  quoteIndex: number,
61	): number => {
62	  const mainItems = step.items.filter(isMainItem);
63	  const components = step.items.filter((item: any) => !isMainItem(item));
64	
65	  const mainBasePremium = mainItems.reduce(
66	    (sum: number, item: any) => sum + premiumForType(item.type),
67	    0,
68	  );
69	
70	  const itemSurcharges = mainItems.reduce(
71	    (sum: number, item: any) => sum + calculateItemSurcharges(item),
72	    0,
73	  );
74	
75	  const componentTotal = calculateComponentPremium(components);
76	  const policyBasePremium = mainBasePremium + componentTotal;
77	
78	  const firstInsurance = policyBasePremium * 0.1;
79	  const loyaltyDiscount =
80	    customer.yearsWithMHPCO >= 2 ? policyBasePremium * 0.2 : 0;
81	  const followUpDiscount =
82	    quoteIndex > 0 ? policyBasePremium * 0.15 : 0;
83	
84	  return Math.ceil(
85	    policyBasePremium +
86	      itemSurcharges +
87	      firstInsurance -
88	      loyaltyDiscount -
89	      followUpDiscount +
90	      PROCESSING_FEE,
91	  );
92	};
93	
94	const calculateInsuranceCap = (items: any[]): number =>
95	  items.reduce((sum: number, item: any) => sum + (INSURANCE_VALUES[item.type] ?? 0), 0) * 2;
96	
97	const calculateClaimResult = (step: any, policy: any, currentCap: number): any => {
98	  const policyCounts = countByType(policy.items);
99	  const damageCounts: Record<string, number> = {};
100	  for (const d of step.incident.damages) {
101	    if (d.amount < 0) {
102	      throw new Error(`Negative damage amount: ${d.amount}`);
103	    }
104	    damageCounts[d.itemType] = (damageCounts[d.itemType] ?? 0) + 1;
105	  }
106	  for (const [type, count] of Object.entries(damageCounts)) {
107	    if (count > (policyCounts[type] ?? 0)) {
108	      throw new Error(`More damage entries for ${type} than policy covers`);
109	    }
110	  }
111	  const totalPayout = step.incident.damages.reduce(
112	    (sum: number, d: any) => {
113	      const policyItem = policy.items.find((i: any) => i.type === d.itemType);
114	      if (!policyItem) {
115	        throw new Error(`Item type ${d.itemType} not in policy`);
116	      }
117	      const reimbursement = policyItem.enchantment >= 8 ? d.amount * 0.5 : d.amount;
118	      return sum + Math.max(0, reimbursement - DEDUCTIBLE);
119	    },
120	    0,
121	  );
122	  const payout = Math.floor(Math.min(totalPayout, currentCap));
123	  return { payout, remainingCap: currentCap - payout };
124	};
125	
126	export const processScenario = (scenario: any): any => {
127	  const policies: any[] = [];
128	  const caps: Record<number, number> = {};
129	  let quoteIndex = 0;
130	  const results = scenario.steps.map((step: any, index: number) => {
131	    if (step.op === "claim") {
132	      const result = calculateClaimResult(step, policies[step.policy], caps[step.policy]);
133	      caps[step.policy] = result.remainingCap;
134	      return result;
135	    }
136	    for (const item of step.items) {
137	      if (!(item.type in BASE_PREMIUMS)) {
138	        throw new Error(`Unknown item type: ${item.type}`);
139	      }
140	    }
141	    const premium = calculateQuotePremium(step, scenario.customer, quoteIndex);
142	    policies[index] = step;
143	    caps[index] = calculateInsuranceCap(step.items);
144	    quoteIndex++;
145	    return { premium };
146	  });
147	  return { results };
148	};
