66	    (sum: number, item: any) => sum + premiumForType(item.type),
67	    0,
68	  );
69	
70	  const itemSurcharges = mainItems.reduce(
71	    (sum: number, item: any) => sum + calculateItemSurcharges(item),
72	    0,
73	  );
74	
75	  const componentTotal = calculateComponentPremium(components);
76	  const policyBasePremium = mainBasePremium + componentTotal;
77	
78	  const firstInsurance = policyBasePremium * 0.1;
79	  const loyaltyDiscount =
80	    customer.yearsWithMHPCO >= 2 ? policyBasePremium * 0.2 : 0;
81	  const followUpDiscount =
82	    quoteIndex > 0 ? policyBasePremium * 0.15 : 0;
83	
84	  return Math.ceil(
85	    policyBasePremium +
86	      itemSurcharges +
87	      firstInsurance -
88	      loyaltyDiscount -
89	      followUpDiscount +
90	      PROCESSING_FEE,
91	  );
92	};
93	
94	const calculateInsuranceCap = (items: any[]): number =>
95	  items.reduce((sum: number, item: any) => sum + (INSURANCE_VALUES[item.type] ?? 0), 0) * 2;
96	
97	const validateClaimDamages = (damages: any[], policyItems: any[]): void => {
98	  const policyCounts = countByType(policyItems);
99	  const damageCounts: Record<string, number> = {};
100	  for (const d of damages) {
101	    if (d.amount < 0) {
102	      throw new Error(`Negative damage amount: ${d.amount}`);
103	    }
104	    if (!(d.itemType in policyCounts)) {
105	      throw new Error(`Item type ${d.itemType} not in policy`);
106	    }
107	    damageCounts[d.itemType] = (damageCounts[d.itemType] ?? 0) + 1;
108	  }
109	  for (const [type, count] of Object.entries(damageCounts)) {
110	    if (count > (policyCounts[type] ?? 0)) {
111	      throw new Error(`More damage entries for ${type} than policy covers`);
112	    }
113	  }
114	};
115	
116	const calculateDamagePayout = (damage: any, policyItem: any): number => {
117	  const reimbursement = policyItem.enchantment >= 8 ? damage.amount * 0.5 : damage.amount;
118	  return Math.max(0, reimbursement - DEDUCTIBLE);
119	};
120	
121	const calculateClaimResult = (step: any, policy: any, currentCap: number): any => {
122	  validateClaimDamages(step.incident.damages, policy.items);
123	  const totalPayout = step.incident.damages.reduce(
124	    (sum: number, d: any) => {
125	      const policyItem = policy.items.find((i: any) => i.type === d.itemType);
126	      return sum + calculateDamagePayout(d, policyItem!);
127	    },
128	    0,
129	  );
130	  const payout = Math.floor(Math.min(totalPayout, currentCap));
131	  return { payout, remainingCap: currentCap - payout };
132	};
133	
134	const validateQuoteItems = (items: any[]): void => {
135	  for (const item of items) {
136	    if (!(item.type in BASE_PREMIUMS)) {
137	      throw new Error(`Unknown item type: ${item.type}`);
138	    }
139	  }
140	};
141	
142	export const processScenario = (scenario: any): any => {
143	  const policies: any[] = [];
144	  const caps: Record<number, number> = {};
145	  let quoteIndex = 0;
146	  const results = scenario.steps.map((step: any, index: number) => {
147	    if (step.op === "claim") {
148	      const result = calculateClaimResult(step, policies[step.policy], caps[step.policy]);
149	      caps[step.policy] = result.remainingCap;
150	      return result;
151	    }
152	    validateQuoteItems(step.items);
153	    const premium = calculateQuotePremium(step, scenario.customer, quoteIndex);
154	    policies[index] = step;
155	    caps[index] = calculateInsuranceCap(step.items);
156	    quoteIndex++;
157	    return { premium };
158	  });
159	  return { results };
160	};
